import{_ as r,o as a,c as t,ag as o}from"./chunks/framework.DGzMGr_a.js";const S=JSON.parse('{"title":"浏览器 & 网络 参考资料","description":"","frontmatter":{},"headers":[],"relativePath":"domains/browser/RESOURCES.md","filePath":"domains/browser/RESOURCES.md","lastUpdated":1783504823000}'),l={name:"domains/browser/RESOURCES.md"};function i(n,e,s,h,f,c){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="浏览器-网络-参考资料" tabindex="-1">浏览器 &amp; 网络 参考资料 <a class="header-anchor" href="#浏览器-网络-参考资料" aria-label="Permalink to &quot;浏览器 &amp; 网络 参考资料&quot;">​</a></h1><p>浏览器原理、HTTP/HTTPS、安全与性能的权威来源。网络协议以 IETF RFC 与 WHATWG 为准。</p><h2 id="加载与架构" tabindex="-1">加载与架构 <a class="header-anchor" href="#加载与架构" aria-label="Permalink to &quot;加载与架构&quot;">​</a></h2><ul><li><a href="https://hpbn.co/" target="_blank" rel="noreferrer">High Performance Browser Networking (O&#39;Reilly)</a> — 浏览器网络栈全景（免费在线版）。Use for: DNS、TCP、TLS、HTTP 全链路。</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/Performance/How_browsers_work" target="_blank" rel="noreferrer">MDN: How browsers work</a> — 导航、解析、渲染概览。Use for: URL 到页面、浏览器架构。</li><li><a href="https://developer.chrome.com/blog/inside-browser-part1" target="_blank" rel="noreferrer">Chromium: Inside look at modern browser</a> — 多进程架构系列。Use for: 浏览器进程模型。</li></ul><h2 id="http-与缓存" tabindex="-1">HTTP 与缓存 <a class="header-anchor" href="#http-与缓存" aria-label="Permalink to &quot;HTTP 与缓存&quot;">​</a></h2><ul><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110: HTTP Semantics</a> — HTTP 语义（方法、状态码、头字段）。Use for: GET/POST、状态码、消息格式。</li><li><a href="https://www.rfc-editor.org/rfc/rfc9111.html" target="_blank" rel="noreferrer">RFC 9111: HTTP Caching</a> — 缓存控制与验证机制。Use for: 强缓存/协商缓存。</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Caching" target="_blank" rel="noreferrer">MDN: HTTP Caching</a> — 缓存头通俗讲解。Use for: 面试快速复述 Cache-Control。</li><li><a href="https://fetch.spec.whatwg.org/" target="_blank" rel="noreferrer">Fetch Living Standard</a> — fetch、CORS、请求/响应模型。Use for: 同源策略、CORS 预检。</li></ul><h2 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h2><ul><li><a href="https://owasp.org/www-project-top-ten/" target="_blank" rel="noreferrer">OWASP Top Ten</a> — Web 安全风险总览。Use for: XSS、CSRF、点击劫持。</li><li><a href="https://cheatsheetseries.owasp.org/cheatsheets/Cross_Site_Scripting_Prevention_Cheat_Sheet.html" target="_blank" rel="noreferrer">OWASP: XSS Prevention Cheat Sheet</a> — XSS 防护清单。Use for: 前端安全题。</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/CSP" target="_blank" rel="noreferrer">MDN: Content Security Policy</a> — CSP 指令与缓解 XSS。Use for: CSP 面试。</li><li><a href="https://web.dev/articles/same-origin-policy" target="_blank" rel="noreferrer">web.dev: Same-origin policy</a> — 同源策略与跨域。Use for: CORS、Cookie 域。</li></ul><h2 id="渲染与性能" tabindex="-1">渲染与性能 <a class="header-anchor" href="#渲染与性能" aria-label="Permalink to &quot;渲染与性能&quot;">​</a></h2><ul><li><a href="https://developer.chrome.com/docs/chromium/renderingng" target="_blank" rel="noreferrer">RenderingNG (Chrome Developers)</a> — 现代 Chromium 渲染管线。Use for: 重排重绘、合成层、GPU。</li><li><a href="https://web.dev/articles/vitals" target="_blank" rel="noreferrer">web.dev: Web Vitals</a> — LCP、INP、CLS 定义与测量。Use for: 性能指标题。</li><li><a href="https://www.w3.org/TR/resource-hints/" target="_blank" rel="noreferrer">W3C: Resource Hints</a> — dns-prefetch、preconnect 等。Use for: 首屏优化。</li></ul><h2 id="存储与离线" tabindex="-1">存储与离线 <a class="header-anchor" href="#存储与离线" aria-label="Permalink to &quot;存储与离线&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/Web_Storage_API" target="_blank" rel="noreferrer">MDN: Web Storage API</a> — localStorage/sessionStorage。Use for: 存储方案对比。</li><li><a href="https://www.w3.org/TR/IndexedDB/" target="_blank" rel="noreferrer">IndexedDB API (W3C)</a> — IndexedDB 规范。Use for: 大容量客户端存储。</li><li><a href="https://www.w3.org/TR/service-workers/" target="_blank" rel="noreferrer">Service Workers (W3C)</a> — Service Worker 生命周期与缓存策略。Use for: PWA、离线缓存。</li></ul><h2 id="实时通信" tabindex="-1">实时通信 <a class="header-anchor" href="#实时通信" aria-label="Permalink to &quot;实时通信&quot;">​</a></h2><ul><li><a href="https://www.rfc-editor.org/rfc/rfc6455" target="_blank" rel="noreferrer">RFC 6455: WebSocket</a> — WebSocket 协议。Use for: WebSocket vs SSE vs 长轮询。</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/Server-sent_events" target="_blank" rel="noreferrer">MDN: Server-sent events</a> — SSE 单向推送。Use for: 实时方案选型。</li></ul>',14)])])}const b=r(l,[["render",i]]);export{S as __pageData,b as default};
